const logLines=[];let lastLoggedError='';function dbgLog(msg,isError=false){try{const t=(performance.now()/1000).toFixed(1);logLines.push('['+t+'s] '+String(msg));while(logLines.length>10)logLines.shift();if(debugLog){debugLog.textContent=logLines.join('\n');if(isError)debugLog.classList.add('hasError')}}catch(_){}}function dbgError(err){const msg=(err&&err.stack)||String(err);if(msg===lastLoggedError)return;lastLoggedError=msg;dbgLog('ERREUR: '+msg,true)}window.addEventListener('error',e=>dbgError((e.error&&e.error.stack)||e.message));window.addEventListener('unhandledrejection',e=>dbgError(e.reason||'Promise rejetée'));const _consoleError=console.error.bind(console);console.error=(...a)=>{dbgLog('console.error: '+a.map(String).join(' '),true);_consoleError(...a)};
let audioCtx=null,masterGain=null,crowdGain=null,crowdFilter=null,crowdMood=0,crowdTarget=.25,lastCrowdChant=0;
function initAudio(){try{if(audioCtx)return;const AC=window.AudioContext||window.webkitAudioContext;if(!AC){dbgLog('AudioContext indisponible');return}audioCtx=new AC();masterGain=audioCtx.createGain();masterGain.gain.value=.58;masterGain.connect(audioCtx.destination);crowdGain=audioCtx.createGain();crowdGain.gain.value=.0;crowdFilter=audioCtx.createBiquadFilter();crowdFilter.type='bandpass';crowdFilter.frequency.value=520;crowdFilter.Q.value=.55;const buf=audioCtx.createBuffer(1,audioCtx.sampleRate*2,audioCtx.sampleRate);const d=buf.getChannelData(0);for(let i=0;i<d.length;i++){const n=(Math.random()*2-1);d[i]=n*.42+(i>0?d[i-1]*.45:0)}const src=audioCtx.createBufferSource();src.buffer=buf;src.loop=true;src.connect(crowdFilter);crowdFilter.connect(crowdGain);crowdGain.connect(masterGain);src.start()}catch(e){dbgError(e)}}
function resumeAudio(){try{initAudio();if(audioCtx&&audioCtx.state==='suspended')audioCtx.resume()}catch(e){dbgError(e)}}
function audioFrame(dt){if(!audioCtx||!crowdGain)return;crowdTarget=clamp(crowdTarget,0,.78);crowdMood+=(crowdTarget-crowdMood)*Math.min(1,dt*1.8);crowdGain.gain.setTargetAtTime(crowdMood,audioCtx.currentTime,.12);crowdFilter.frequency.setTargetAtTime(420+crowdMood*720,audioCtx.currentTime,.18);if(!gameOver&&menu.style.display==='none'){crowdTarget=Math.max(.18,crowdTarget-dt*.045);lastCrowdChant-=dt;if(lastCrowdChant<=0){lastCrowdChant=rand(2.2,4.8);if(Math.random()<.42)sfxChant(Math.random()<.62?'team':'push')}}}
function crowdSet(v){crowdTarget=Math.max(crowdTarget,v)}
function updateCrowd(dt){audioFrame(dt)}
function tone(freq,dur=0.12,type='sine',gain=.15,slide=0){if(!audioCtx||!masterGain)return null;const t=audioCtx.currentTime,o=audioCtx.createOscillator(),g=audioCtx.createGain();o.type=type;o.frequency.setValueAtTime(freq,t);if(slide)o.frequency.exponentialRampToValueAtTime(Math.max(30,freq*slide),t+dur);g.gain.setValueAtTime(gain,t);g.gain.exponentialRampToValueAtTime(.0001,t+dur);o.connect(g);g.connect(masterGain);o.start(t);o.stop(t+dur+.02);return o}
function noise(dur=.12,gain=.12,filter=900){if(!audioCtx||!masterGain)return;const t=audioCtx.currentTime,buf=audioCtx.createBuffer(1,Math.max(1,Math.floor(audioCtx.sampleRate*dur)),audioCtx.sampleRate),d=buf.getChannelData(0);for(let i=0;i<d.length;i++)d[i]=Math.random()*2-1;const s=audioCtx.createBufferSource(),f=audioCtx.createBiquadFilter(),g=audioCtx.createGain();f.type='bandpass';f.frequency.value=filter;f.Q.value=.8;g.gain.setValueAtTime(gain,t);g.gain.exponentialRampToValueAtTime(.0001,t+dur);s.buffer=buf;s.connect(f);f.connect(g);g.connect(masterGain);s.start(t);s.stop(t+dur+.02)}
function sfxPass(lob=false,power=.35){resumeAudio();tone(lob?420:620,.07,'triangle',lob?.10:.075,lob?.65:1.25);noise(lob?.16:.07,lob?.055:.035,lob?620:1200);crowdSet(lob?.42:.30)}
