function sfxGoal(){resumeAudio();crowdTarget=.82;noise(.55,.28,760);tone(440,.16,'square',.12,1.5);setTimeout(()=>tone(660,.18,'square',.11,1.4),120);setTimeout(()=>tone(880,.22,'square',.10,1.2),250);for(let i=0;i<7;i++)setTimeout(()=>sfxChant('goal'),i*180)}
