function hexRgb(h){h=(h||'#000').replace('#','');if(h.length===3)h=h.split('').map(x=>x+x).join('');const n=parseInt(h,16);return {r:(n>>16)&255,g:(n>>8)&255,b:n&255}}
function colorDist(a,b){const A=hexRgb(a),B=hexRgb(b);return Math.hypot(A.r-B.r,A.g-B.g,A.b-B.b)}
function luminance(h){const c=hexRgb(h);return .2126*c.r+.7152*c.g+.0722*c.b}
function makeKit(color,stripe){return {color, stripe}}
function homeKit(c){return makeKit(c.color,c.stripe)}
function awayKit(c){const light=luminance(c.color)>170;const body=light?'#111111':'#f7f7f7';return makeKit(body,c.color)}
function invertKit(c){return makeKit(c.stripe,c.color)}
function safeKit(c){return makeKit(luminance(c.color)>170?'#0f1820':'#ffffff',c.stripe||c.color)}
function kitScore(a,b){return colorDist(a.color,b.color)+colorDist(a.stripe,b.stripe)*.6+colorDist(a.color,b.stripe)*.25+colorDist(a.stripe,b.color)*.25}
function resolveMatchKits(){teamAKit=homeKit(teamA);const options=[homeKit(teamB),invertKit(teamB),awayKit(teamB),safeKit(teamB)];let best=options[0],bestScore=-1;for(const k of options){const sc=kitScore(teamAKit,k);if(sc>bestScore){bestScore=sc;best=k}}if(bestScore<170)teamAKit=awayKit(teamA);teamBKit=best}
function teamKit(team){return team===TA?teamAKit:teamBKit}
