function pickMatchEnvironment(){const tods=['morning','noon','evening'];const weathers=['clear','sunny','rain','storm','snow'];matchEnv={tod:tods[Math.floor(Math.random()*tods.length)],weather:weathers[Math.floor(Math.random()*weathers.length)]};if(mode==='training'&&Math.random()<.65)matchEnv.weather='clear';weatherChangeT=rand(38,72);weatherParticles=[];lightningT=0;}
function maybeChangeWeather(dt){if(menu.style.display!=='none'||gamePaused||gameOver||mode==='training')return;weatherChangeT-=dt;if(weatherChangeT>0)return;weatherChangeT=rand(38,76);if(Math.random()>.42)return;const current=matchEnv.weather;const soft=['clear','sunny','rain'];const rough=['clear','rain','storm','snow'];const pool=(current==='storm'||current==='snow')?soft:(Math.random()<.82?soft:rough);let next=current,guard=0;while(next===current&&guard++<8)next=pool[Math.floor(rand(0,pool.length))];matchEnv.weather=next;weatherParticles=[];lightningT=0;show(next==='clear'?'LE CIEL SE DÉGAGE':next==='sunny'?'ÉCLAIRCIE':next==='rain'?'LA PLUIE ARRIVE':next==='storm'?'ORAGE AU STADE !':'QUELQUES FLOCONS');}
function updateWeather(dt){maybeChangeWeather(dt);const w=matchEnv.weather;const spawnCount=w==='rain'?4:w==='storm'?6:w==='snow'?2:0;for(let i=0;i<spawnCount;i++){if(w==='rain'||w==='storm')weatherParticles.push({x:rand(-30,W+30),y:rand(-20,H),vx:-2.4-rand(0,.8),vy:7.2+rand(0,2.4),r:rand(1,2),life:1});else if(w==='snow')weatherParticles.push({x:rand(0,W),y:rand(-10,H),vx:rand(-.25,.25),vy:.8+rand(0,.8),r:rand(1,2.5),life:1});}const f=dt*60;weatherParticles.forEach(p=>{p.x+=p.vx*f*.35;p.y+=p.vy*f*.35;p.life-=.008*f});weatherParticles=weatherParticles.filter(p=>p.life>0&&p.y<H+20&&p.x>-50&&p.x<W+50);if(w==='storm'&&Math.random()<.006)lightningT=.16;if(lightningT>0)lightningT=Math.max(0,lightningT-dt);}
function drawWeather(){if(matchEnv.weather==='rain'||matchEnv.weather==='storm'){ctx.strokeStyle=matchEnv.weather==='storm'?'rgba(210,230,255,.42)':'rgba(180,220,255,.32)';ctx.lineWidth=1.4;for(const p of weatherParticles){ctx.beginPath();ctx.moveTo(p.x,p.y);ctx.lineTo(p.x+5,p.y+12);ctx.stroke();}}else if(matchEnv.weather==='snow'){ctx.fillStyle='rgba(255,255,255,.8)';for(const p of weatherParticles){ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);ctx.fill();}}if(lightningT>0){ctx.fillStyle='rgba(255,255,255,'+(lightningT*1.8)+')';ctx.fillRect(0,0,W,H);}}
