function drawDayMood(){let c='rgba(0,0,0,0)';if(matchEnv.tod==='morning')c='rgba(255,210,120,.08)';else if(matchEnv.tod==='evening')c='rgba(255,120,80,.12)';if(matchEnv.weather==='storm')c='rgba(60,90,120,.18)';ctx.fillStyle=c;ctx.fillRect(0,0,W,H);}
function updateCamera(dt){if(!ball)return;const focus=controlled?controlled.pos.clone().mul(.62).add(ball.pos.clone().mul(.38)):ball.pos.clone();cam.tx=clamp(W/2-focus.x,-18,18);cam.ty=clamp(H/2-focus.y,-12,12);cam.x+=(cam.tx-cam.x)*Math.min(1,dt*4.5);cam.y+=(cam.ty-cam.y)*Math.min(1,dt*4.5);}
function beginKickoffSequence(kick){kickoffSetupT=1.15;kickoffKickTeam=kick;players.forEach(p=>{if(p.dead){p.dead=false;p.respawn=0;p.stun=16}p.hasBall=false;p.control=false;p.kickTarget=p.spawn.clone();p.vel.set(0,0)});if(ball){ball.owner=null;ball.ignorePlayer=null;ball.ignoreT=0;ball.vel.set(0,0);ball.pos.set(W/2,H/2);ball.z=0;ball.vz=0;}show('REPLACEMENT...')}
function kickoffUpdate(dt){kickoffSetupT=Math.max(0,kickoffSetupT-dt);let ready=0,total=0;for(const p of players){if(!p.kickTarget)continue;total++;const to=p.kickTarget.clone().sub(p.pos);const d=to.len();if(d<5){ready++;p.pos.set(p.kickTarget.x,p.kickTarget.y);p.vel.set(0,0)}else{const dir=to.norm();p.vel=dir.clone().mul(Math.min(2.4,d*.09));p.pos.add(p.vel)}p.face=new V(p.team===TA?1:-1,0)}ball.pos.set(W/2,H/2);ball.vel.set(0,0);ball.z=0;ball.vz=0;ball.owner=null;if(kickoffSetupT<=0||(total>0&&ready>=total)){kickoffSetupT=0;players.forEach(p=>{p.kickTarget=null;p.vel.set(0,0);p.control=false;p.hasBall=false});const starter=players.find(p=>p.team===kickoffKickTeam&&p.role==='mid')||players.find(p=>p.team===kickoffKickTeam&&p.role==='striker')||players.find(p=>p.team===kickoffKickTeam&&!p.dead);if(starter){starter.pos.set(W/2,H/2);attach(starter)}const user=players.find(p=>p.team===TA&&p.role==='mid')||players.find(p=>p.team===TA&&p.role==='striker')||players.find(p=>p.team===TA&&!p.dead);if(user)setControl(user);show('REMISE EN JEU !')}}
