ai(){const ownDir=this.team===TA?1:-1;let target=this.spawn.clone();const hasEnemyBall=ball.owner&&ball.owner.team!==this.team,hasOurBall=ball.owner&&ball.owner.team===this.team;const free=!ball.owner;const chaser=closestToBall(this.team),second=secondClosestToBall(this.team);if(this.forcedTarget&&this.forcedTarget.t>0){this.forcedTarget.t--;target=this.forcedTarget.pos.clone();this.intent='appel'}else if(free){const interceptor=bestInterceptor(this.team);if(interceptor===this){target=interceptPointFor(this);this.intent=ball.z>12?'anticipe lob':'intercepte'}else{target=this.tacticalHome(ball.pos);this.intent='bloc'}}else if(hasEnemyBall){const carrier=ball.owner;const dist=V.dist(this.pos,carrier.pos);const carrierIdle=carrier.vel.len()<.35,attackSkill=(this.country.ai+this.country.tackle+this.country.speed)/3;const dangerous=isDangerZone(carrier,this.team);const pressRange=(135+120*attackSkill+75*(carrierIdle?1:0)+60*(dangerous?1:0))*BAL.press*BAL.aggro;const isMainPresser=chaser===this&&this.role!=='keeper';const isSecondPresser=second===this&&this.role==='mid'&&dangerous&&dist<pressRange*.86;const pressingAllowed=mode!=='training'&&(isMainPresser||isSecondPresser)&&dist<pressRange;if(pressingAllowed){target=pressingPoint(this,carrier,isSecondPresser);this.intent=isSecondPresser?'coupe passe':carrierIdle?'vole':'presse';if(dist<38&&this.cd<=0&&(carrier.vel.len()<1.8||dangerous))slideTackle(this)}else{target=this.defensiveSlot(carrier.pos);this.intent=this.role==='defender'?'ligne':'couvre'}}else if(hasOurBall){if(ball.owner===this){this.intent='porte';aiWithBall(this)}else{target=this.supportSlot(ball.owner);this.intent=this.role==='striker'?'appel':'solution'}}else{this.intent='replace'}target.x=clamp(target.x,field.x+35,field.x+field.w-35);target.y=clamp(target.y,field.y+35,field.y+field.h-35);const to=target.sub(this.pos);if(to.len()>6){const roleMul=this.role==='keeper'?.58:this.role==='defender'?.84:this.role==='mid'?1.00:1.08;this.vel.add(to.norm().mul(.122*BAL.speed*BAL.ai*this.country.speed*this.country.ai*roleMul*(this.captain?1+BAL.captain:1)*(mode==='training'?0.55:0.82)*(1+0.18*(BAL.aggro-1))))}}
