const LOB_WALL_BOUNCE_Z=18;
class Ball{
constructor(){this.pos=new V(W/2,H/2);this.vel=new V();this.r=8;this.owner=null;this.lastKicker=null;this.ignorePlayer=null;this.ignoreT=0;this.spin=0;this.drb=0;this.z=0;this.vz=0;this.lob=false;this.airWallT=0}
update(){
 if(this.owner){
  this.z=0;this.vz=0;this.lob=false;
  const speed=this.owner.vel.len();
  const f=(speed>.12?this.owner.vel.clone().norm():this.owner.face.clone().norm());
  const side=new V(-f.y,f.x);const run=clamp(speed/5.2,0,1);
  if(speed>.12)this.drb+=speed*.11;
  const tap=(Math.floor(this.drb)%2)*2-1;const sideOffset=tap*.9*run;const push=20+2.4*run;
  this.pos.set(this.owner.pos.x+f.x*push+side.x*sideOffset,this.owner.pos.y+f.y*push+side.y*sideOffset);
  if(speed>.12)this.spin+=speed*.055;
  this.vel.set(0,0);return
 }
 if(this.ignoreT>0)this.ignoreT--;
 if(this.airWallT>0)this.airWallT--;
 this.pos.add(this.vel);
 if(this.z>0||this.vz>0){this.z+=this.vz;this.vz-=.42;if(this.z<=0){this.z=0;this.vz=0;this.lob=false;pop(this.pos.x,this.pos.y,'#ffffff',7)}}
 this.spin+=this.vel.len()*.05;this.vel.mul(.986);if(this.vel.len()<.06)this.lastKicker=null;
 if(this.pos.x-this.r<field.x){
  if(canScoreBall(this)){goal(TB,this.pos.y);return}
  this.pos.x=field.x+this.r;
  if(inGoal(this.pos.y)&&this.z>=GOAL_CROSSBAR_Z)this.airBounceX(1,'LOB TROP HAUT !',true);
  else if(this.z>LOB_WALL_BOUNCE_Z)this.airBounceX(1,'LOB SUR LE MUR !',false);
  else this.groundBounceX(1);
 }
 if(this.pos.x+this.r>field.x+field.w){
  if(canScoreBall(this)){goal(TA,this.pos.y);return}
  this.pos.x=field.x+field.w-this.r;
  if(inGoal(this.pos.y)&&this.z>=GOAL_CROSSBAR_Z)this.airBounceX(-1,'LOB TROP HAUT !',true);
  else if(this.z>LOB_WALL_BOUNCE_Z)this.airBounceX(-1,'LOB SUR LE MUR !',false);
  else this.groundBounceX(-1);
 }
 if(this.pos.y-this.r<field.y){this.pos.y=field.y+this.r;if(this.z>LOB_WALL_BOUNCE_Z)this.airBounceY(1,'LOB SUR LA LIGNE !');else this.groundBounceY(1)}
 if(this.pos.y+this.r>field.y+field.h){this.pos.y=field.y+field.h-this.r;if(this.z>LOB_WALL_BOUNCE_Z)this.airBounceY(-1,'LOB SUR LA LIGNE !');else this.groundBounceY(-1)}
 const lethal=this.vel.len()>12.2;
 for(const p of players){if(p.dead)continue;if(this.ignoreT>0&&p===this.ignorePlayer)continue;if(this.z>20&&!canVolleyPrep(p))continue;if(V.dist(this.pos,p.pos)<this.r+p.r){if(lethal&&this.lastKicker&&this.lastKicker!==p&&p.team!==this.lastKicker.team){brutalKO(p,this.lastKicker,'FATAL SHOT !');this.vel.mul(.78);continue}else{attach(p);break}}}
 const sp=this.vel.len();
 if(sp>3.2){const c=this.z>10?'#ffffff':sp>13?'#ff2a13':sp>8?'#ffd32d':'#53d7ff';for(let i=0;i<(sp>12?3:1);i++)particles.push({x:this.pos.x-this.vel.x*.8+rand(-5,5),y:this.pos.y-this.vel.y*.8+rand(-5,5)-this.z*.35,vx:rand(-.4,.4),vy:rand(-.4,.4),life:rand(7,18),c,s:rand(3,6)})}
}
groundBounceX(dir){this.vel.x=dir*Math.abs(this.vel.x)*.88;wallHit(this.pos.x,this.pos.y)}
groundBounceY(dir){this.vel.y=dir*Math.abs(this.vel.y)*.88;wallHit(this.pos.x,this.pos.y)}
airBounceX(dir,msg,isGoalTop){this.vel.x=dir*Math.abs(this.vel.x)*(isGoalTop?.58:.42);this.vel.y*=.86;this.vz*=isGoalTop?.35:.58;this.z=Math.max(0,this.z-(isGoalTop?5:2));this.airWallFx(msg)}
airBounceY(dir,msg){this.vel.y=dir*Math.abs(this.vel.y)*.42;this.vel.x*=.90;this.vz*=.58;this.z=Math.max(0,this.z-2);this.airWallFx(msg)}
airWallFx(msg){wallHit(this.pos.x,this.pos.y);pop(this.pos.x,this.pos.y-this.z,'#ffffff',10);if(this.airWallT<=0){show(msg);this.airWallT=28}}
draw(){const sp=this.vel.len();ctx.save();ctx.globalAlpha=clamp(1-this.z/90,.25,.75);ctx.fillStyle='rgba(0,0,0,.42)';ctx.beginPath();ctx.ellipse(this.pos.x,this.pos.y+6,this.r+this.z*.045,Math.max(3,this.r*.45-this.z*.015),0,0,Math.PI*2);ctx.fill();ctx.globalAlpha=1;ctx.translate(this.pos.x,this.pos.y-this.z);ctx.rotate(this.spin);ctx.fillStyle=this.z>10?'#ffffff':sp>13?'#ff3218':sp>8?'#ffd32d':sp>3?'#53d7ff':'#f8f8ef';ctx.beginPath();ctx.arc(0,0,this.r,0,Math.PI*2);ctx.fill();ctx.strokeStyle='#111';ctx.lineWidth=2;ctx.stroke();ctx.fillStyle='#111';ctx.fillRect(-2,-7,4,4);ctx.fillRect(3,-1,4,4);ctx.restore()}
}

