function profileFor(country,index){
  const arr=TEAM_PROFILES[country.name];
  if(arr&&arr[index]){const [name,skin,hairStyle,hairColor]=arr[index];return {name,skin,hairStyle,hairColor};}
  const tones=[SKIN.light,SKIN.tan,SKIN.brown,SKIN.dark,SKIN.fair];
  const styles=['short','flat','curly','shaved','mohawk','beard'];
  const hairs=[HAIR.black,HAIR.brown,HAIR.dark,HAIR.blond];
  return {name:fallbackNames[index%fallbackNames.length],skin:tones[(country.id+index)%tones.length],hairStyle:styles[(country.id*2+index)%styles.length],hairColor:hairs[(country.id+index*3)%hairs.length]};
}
function drawHair(g,style,color,s){
  const h=s/2;g.save();g.fillStyle=color||HAIR.black;
  if(style==='short'){g.fillRect(-h,-h-3,s,7);g.fillRect(-h,-h+3,5,4);g.fillRect(h-5,-h+3,5,4)}
  else if(style==='flat'){g.fillRect(-h-1,-h-5,s+2,8)}
  else if(style==='curly'){for(let i=0;i<5;i++)g.fillRect(-h+i*7,-h-5-(i%2)*2,8,8)}
  else if(style==='mohawk'){g.fillRect(-4,-h-7,8,14)}
  else if(style==='shaved'){g.globalAlpha=.45;g.fillRect(-h,-h,s,5);g.globalAlpha=1}
  else if(style==='long'){g.fillRect(-h,-h-3,s,7);g.fillRect(-h-2,-h+4,5,14);g.fillRect(h-3,-h+4,5,14)}
  else if(style==='band'){g.fillRect(-h,-h+1,s,4);g.fillStyle='#ffffff';g.fillRect(-h,-h+4,s,2)}
  else if(style==='beard'){g.fillRect(-h,-h-2,s,6);g.fillRect(-8,2,16,7);g.fillRect(-5,8,10,3)}
  g.restore();
}

function currentMenuItems(){return Array.from(countryList.querySelectorAll('[data-menu-item]'))}
function setMenuFocus(i){const items=currentMenuItems();if(!items.length)return;menuFocus=(i+items.length)%items.length;items.forEach((el,idx)=>el.classList.toggle('focused',idx===menuFocus));items[menuFocus].scrollIntoView({block:'nearest',inline:'nearest'})}
function statBadge(icon,label,val){return `<span class="statBadge">${icon} ${label} ${stars(val)}</span>`}
function lineupFor(team,tacticId){const t=TACTICS[tacticId]||TACTICS.balanced;let slots=t.slots;if(matchSize===2)slots=[t.slots[0],t.slots[4]];else if(matchSize===3)slots=[t.slots[0],t.slots[3],t.slots[4]];else if(matchSize===5)slots=[t.slots[0],t.slots[1],t.slots[3],t.slots[4],t.slots[5]||t.slots[2]];return slots.map((s,i)=>{const x=team===TA?field.x+s[1]:field.x+field.w-s[1];return [s[0],x,H/2+s[2],i]})}function createTeams(){players=[];const a=lineupFor(TA,tacticA),b=lineupFor(TB,tacticB);a.forEach((s,i)=>players.push(new Player(s[1],s[2],TA,s[0],teamA,i)));if(mode!=='training')b.forEach((s,i)=>players.push(new Player(s[1],s[2],TB,s[0],teamB,i)));if(!players.some(p=>p.team===TA&&p.role==='keeper'))players.push(new Player(field.x+70,H/2,TA,'keeper',teamA,0));if(mode!=='training'&&!players.some(p=>p.team===TB&&p.role==='keeper'))players.push(new Player(field.x+field.w-70,H/2,TB,'keeper',teamB,0));players.forEach(p=>{if(p.captain){p.energy=1;p.intent='CAPITAINE';}});createBench();setControl(players.find(p=>p.team===TA&&p.role==='mid')||players.find(p=>p.team===TA&&p.role==='striker')||players.find(p=>p.team===TA&&p.role!=='keeper')||players[0]);if(controlMode!=='solo'){const t=controlMode==='pvp'?TB:TA;setControl2(players.find(p=>p.team===t&&p!==controlled&&p.role==='mid')||players.find(p=>p.team===t&&p!==controlled&&p.role==='striker')||players.find(p=>p.team===t&&p!==controlled&&p.role!=='keeper')||players.find(p=>p.team===t&&p!==controlled))}}function captainName(team){const cap=players.find(p=>p.team===team&&p.captain);return cap?cap.name:(team===TA?'Cap. '+teamA.name.slice(0,3).toUpperCase():'Cap. '+teamB.name.slice(0,3).toUpperCase())}function teamCaptain(team){return players.find(p=>p.team===team&&p.captain&&!p.dead)||players.find(p=>p.team===team&&!p.dead)}
function reset(kick,entrance=false){createTeams();ball=new Ball();const starter=players.find(p=>p.team===kick&&p.role==='mid')||players.find(p=>p.team===kick&&p.role==='striker')||players[3];particles=[];bloodDecals=[];oneTwo=null;shootCharge=0;passCharge=0;if(entrance){players.forEach(p=>{p.dead=false;p.respawn=0;p.stun=0;p.hasBall=false;p.control=false;p.kickTarget=p.pos.clone();const sx=p.team===TA?field.x-80-rand(0,28):field.x+field.w+80+rand(0,28);p.pos.set(sx,p.kickTarget.y+rand(-16,16));p.vel.set(0,0);});ball.pos.set(W/2,H/2);ball.vel.set(0,0);ball.owner=null;ball.z=0;ball.vz=0;}else{attach(starter);if(starter){starter.pos.set(W/2,H/2);starter.vel.set(0,0)}}}
function createBench(){bench=[];const make=(team,country,count,top)=>{for(let i=0;i<count;i++){const x=team===TA?field.x+115+i*42:field.x+field.w-115-i*42;const y=top?field.y-30:field.y+field.h+30;const prof=profileFor(country,6+i);bench.push({team,country,slot:i,x,y,used:false,top,name:prof.name,skin:prof.skin,hairStyle:prof.hairStyle,hairColor:prof.hairColor,role:['defender','mid','striker','mid','striker'][i%5]})}};make(TA,teamA,5,false);if(mode!=='training')make(TB,teamB,5,true)}
function drawBench(){for(const b of bench){if(b.used)continue;const bob=Math.sin(gameTick*.08+b.slot)*2;drawMiniBenchPlayer(b.x,b.y+bob,b,22);if(b.slot%2===0){ctx.fillStyle='#f8f8ef';ctx.beginPath();ctx.arc(b.x+18,b.y+5,5,0,Math.PI*2);ctx.fill();ctx.strokeStyle='#111';ctx.lineWidth=1;ctx.stroke()}}}
function drawMiniBenchPlayer(x,y,b,s){const h=s/2;ctx.save();ctx.translate(x,y);ctx.fillStyle='rgba(0,0,0,.28)';ctx.fillRect(-h+3,-h+8,s,s*.62);ctx.fillStyle=b.skin||'#f0c58d';ctx.fillRect(-h,-h,s,s);drawHair(ctx,b.hairStyle,b.hairColor,s);ctx.fillStyle='#111';ctx.fillRect(-1,-h+4,3,7);const kit=teamKit(b.team);ctx.fillStyle=kit.color;ctx.fillRect(-h,0,s,h);ctx.fillStyle=kit.stripe;ctx.fillRect(-h,h-5,s,5);ctx.restore()}
function callSubstituteFor(victim){const b=bench.find(x=>x.team===victim.team&&!x.used);if(!b)return null;b.used=true;const sub=new Player(b.x,b.y,victim.team,victim.role,victim.country,victim.i);sub.name=b.name;sub.skin=b.skin;sub.hairStyle=b.hairStyle;sub.hairColor=b.hairColor;sub.captain=false;sub.spawn=victim.spawn.clone();sub.forcedTarget={pos:victim.spawn.clone(),t:190};sub.stun=0;sub.vel=new V((victim.team===TA?1:-1)*.6,b.top?.3:-.3);players.push(sub);pop(b.x,b.y,'#ffd34a',22);show('REMPLAÇANT : '+sub.name);return sub}
function attach(p){if(!p||p.dead)return;if(ball.owner)ball.owner.hasBall=false;ball.owner=p;p.hasBall=true;if(p.team===TA)setControl(p)}
function release(dir,pow,lob=0){const d=dir.clone().norm();if(ball.owner){ball.lastKicker=ball.owner;ball.ignorePlayer=ball.owner;ball.ignoreT=lob>0?24:14;ball.owner.hasBall=false;}ball.owner=null;ball.pos.add(d.clone().mul(lob>0?16:11));ball.vel=d.mul(pow);if(lob>0){ball.z=8;ball.vz=lob;ball.lob=true}}
function rawAimVector(){const d=new V();if(keys.z||keys.arrowup)d.y-=1;if(keys.s||keys.arrowdown)d.y+=1;if(keys.q||keys.a||keys.arrowleft)d.x-=1;if(keys.d||keys.arrowright)d.x+=1;d.x+=mobileMove.x+gpMove.x;d.y+=mobileMove.y+gpMove.y;return d}
function aimDir(p){const d=rawAimVector();return d.len()>.18?d.norm():p.face.clone()}
function assistedDirToMate(p,m){const lead=(m.role==='striker'?28:18);const dir=m.pos.clone().add(m.vel.clone().mul(15)).add(new V((p.team===TA?1:-1)*lead,0)).sub(p.pos);return dir.len()>.01?dir.norm():aimDir(p)}
function manualPassIntoSpace(p){sfxPass(false,.38);const dir=aimDir(p);const spacePoint=p.pos.clone().add(dir.clone().mul(310));const runner=bestRunnerToSpace(p,spacePoint);const pow=(runner?7.2:6.8)*BAL.pass*p.country.pass;release(dir,pow);ball.lastKicker=p;pop(p.pos.x,p.pos.y,'#ffe45c',10);show('PASSE DANS L’ESPACE');if(runner){runner.forcedTarget={pos:spacePoint,t:105};if(p.team===TA)setControl(runner)}return runner}
function lobPass(p,charge){sfxPass(true,charge);const dir=aimDir(p);const spacePoint=p.pos.clone().add(dir.clone().mul(380+charge*170));const runner=bestRunnerToSpace(p,spacePoint);const pow=(8.4+charge*4.8)*BAL.pass*p.country.pass;release(dir,pow,7+charge*8);ball.lastKicker=p;pop(p.pos.x,p.pos.y,'#ffffff',16);show(charge>.62?'LONGUE PASSE LOBÉE !':'PASSE LOBÉE');if(runner){runner.forcedTarget={pos:spacePoint,t:150};if(p.team===TA)setControl(runner)}return runner}
function bestRunnerToSpace(p,spacePoint){let best=null,score=1e9;for(const m of players){if(m.team!==p.team||m===p||m.dead)continue;const d=V.dist(m.pos,spacePoint);const forward=p.team===TA?spacePoint.x-m.pos.x:m.pos.x-spacePoint.x;const s=d-forward*.18+(m.role==='striker'?-30:0);if(s<score){score=s;best=m}}return best}
function doPass(p){if(!p.hasBall){if(canPlayBall(p)){volleyPass(p);return true}return false}if(oneTwo&&oneTwo.returnTo&&oneTwo.from===p&&V.dist(p.pos,oneTwo.returnTo.pos)<305){targetPass(p,oneTwo.returnTo,true);oneTwo=null;show('UNE-DEUX !');return true}const raw=rawAimVector();const hasDirectionalIntent=raw.len()>.32;const mate=bestMate(p);if(hasDirectionalIntent&&(!mate||mate.align<.46)){manualPassIntoSpace(p);return true}if(mate&&mate.score>4){oneTwo={from:mate.player,returnTo:p,t:1.9};targetPass(p,mate.player,false);setControl(mate.player);return true}manualPassIntoSpace(p);return true}
function targetPass(p,mate,ret){sfxPass(false,.32);const dir=assistedDirToMate(p,mate);release(dir,6.8*BAL.pass*p.country.pass);pop(p.pos.x,p.pos.y,'#ffe45c',8);if(ret)setControl(mate)}
function bestMate(p){const mates=players.filter(m=>m.team===p.team&&m!==p&&!m.dead);let best=null,score=-1e9,bestAlign=-1;const aim=aimDir(p);for(const m of mates){const to=m.pos.clone().sub(p.pos),d=to.len(),dir=to.clone().norm();const rawAlign=dir.x*aim.x+dir.y*aim.y;const align=Math.max(-.35,rawAlign);const forward=p.team===TA?m.pos.x-p.pos.x:p.pos.x-m.pos.x;let s=align*72-d*.085+forward*.10;if(m.role==='striker')s+=18;if(laneBlocked(p.pos,m.pos,p.team))s-=26;if(s>score){score=s;best=m;bestAlign=rawAlign}}return best?{player:best,score,align:bestAlign}:null}
function shoot(p,charge){if(!p.hasBall)return;sfxShoot(charge);const aim=aimDir(p);const goalDir=new V(p.team===TA?field.x+field.w:field.x,H/2+rand(-field.goal*.32,field.goal*.32)).sub(p.pos).norm();const assist=charge>.45?.42:.25;const dir=aim.mul(1-assist).add(goalDir.mul(assist)).norm();const pow=((7.2+charge*8.8)*BAL.force)*p.country.power;release(dir,pow);pop(p.pos.x,p.pos.y,charge>.75?'#ff2600':'#ff4a24',14+charge*24);if(charge>.75)show('TIR CARNAGE !');else show('TIR LIBRE');shake+=4+charge*8}
function canPlayBall(p){return !ball.owner&&!p.dead&&ball.z<24&&V.dist(p.pos,ball.pos)<44}
function canVolleyPrep(p){return !ball.owner&&!p.dead&&V.dist(p.pos,ball.pos)<72&&ball.z<58}
function volleyShoot(p,charge){sfxVolley(charge);charge=clamp(charge,.18,1);const gx=p.team===TA?field.x+field.w:field.x,gy=H/2+rand(-field.goal*.24,field.goal*.24);const dir=new V(gx,gy).sub(p.pos).norm();ball.lastKicker=p;ball.ignorePlayer=p;ball.ignoreT=14;ball.vel=dir.mul((12.0+charge*18.5)*BAL.force*p.country.power);ball.vz=charge>.28?2.4+charge*5.2:Math.max(0,ball.vz*.45);ball.z=Math.max(ball.z,charge>.28?10:ball.z);pop(ball.pos.x,ball.pos.y,'#ffffff',18+charge*26);show(charge>.72?'REPRISE FUSÉE !':charge>.28?'REPRISE PRÉCHARGÉE !':'REPRISE !');shake+=7+charge*15}
function volleyPass(p,charge=0){sfxPass(charge>.2,charge);const m=bestMate(p);if(charge>.2){const dir=aimDir(p);ball.lastKicker=p;ball.ignorePlayer=p;ball.ignoreT=12;ball.vel=dir.mul((7.8+charge*4.2)*BAL.pass*p.country.pass);ball.z=Math.max(ball.z,8);ball.vz=4+charge*6;show('DÉVIATION LOBÉE !');pop(ball.pos.x,ball.pos.y,'#ffffff',14);return true}if(m&&m.score>12){ball.lastKicker=p;ball.vel=m.player.pos.clone().sub(ball.pos).norm().mul(6.9*BAL.pass*p.country.pass);oneTwo={from:m.player,returnTo:p,t:1.9};setControl(m.player);show('PASSE EN UNE TOUCHE !');pop(ball.pos.x,ball.pos.y,'#53d7ff',12);return true}const dir=aimDir(p);ball.lastKicker=p;ball.vel=dir.mul(6.5*BAL.pass*p.country.pass);show('DÉVIATION DANS L’ESPACE');pop(ball.pos.x,ball.pos.y,'#53d7ff',12);return true}
function resolveSlideHit(p){if(p.slideHit<=0)return;p.slideHit=0;const dir=p.slideDir.clone();let touched=false;for(const o of players){if(o.dead||o.team===p.team)continue;if(V.dist(o.pos,p.pos)<42){touched=true;o.stun=34;gore(o.pos.x,o.pos.y,16);dirtBurst(o.pos.x,o.pos.y,dir,16);shake+=7;if(o.hasBall){o.hasBall=false;ball.owner=null;ball.lastKicker=p;ball.vel=dir.clone().mul(7.6*BAL.tackle);ball.ignorePlayer=p;ball.ignoreT=12;sfxTackle(true);show('TACLE RÉUSSI !')}else if(Math.random()<.12){brutalKO(o,p,'TACLE MEURTRIER !')}}}if(!touched){p.tired=Math.max(p.tired,92);show('TACLE RATÉ !')}}function slideTackle(p){if(p.cd>0||p.slideT>0)return;sfxTackle(false);const dir=aimDir(p);p.slideDir=dir.clone();p.face=dir.clone();p.cd=mode==='training'?42:76;p.slideT=30;p.slideHit=1;p.stun=0;p.sprintHeld=0;p.sprintTriggered=false;p.vel.add(dir.clone().mul((p.hasBall?2.0:3.6)*BAL.tackle*p.country.tackle));p.energy=clamp(p.energy-.10,.40,1);pop(p.pos.x,p.pos.y,p.hasBall?'#53d7ff':'#ffffff',p.hasBall?8:14);dirtBurst(p.pos.x,p.pos.y,dir,p.hasBall?10:18);if(p.hasBall){release(dir,5.2*BAL.pass,.0);show('TACLE GLISSÉ AVEC BALLON')}}
function startSprint(p){if(p.sprintCd>0||p.tired>0){pop(p.pos.x,p.pos.y,'#ff3333',5);show('SPRINT EN COOLDOWN');return}const cd=Math.round(BAL.sprintCd/(.92+.12*p.country.speed));p.sprintCd=cd;p.sprintCdMax=cd;p.sprintActive=Math.round(48*BAL.sprint);p.sprintActiveMax=Math.max(1,p.sprintActive);p.energy=clamp(p.energy-.12,.45,1);pop(p.pos.x,p.pos.y,p.hasBall?'#53d7ff':'#ffffff',18);show(p.hasBall?'SPRINT !':'SPRINT DEFENSIF !')}
function aiWithBall(p){const ownDir=p.team===TA?1:-1;const gx=p.team===TA?field.x+field.w:field.x;const attack=(p.country.power+p.country.pass+p.country.ai)/3;const distGoal=Math.abs(p.pos.x-gx),danger=Math.abs(p.pos.y-H/2)<field.goal*.72;const pressure=pressureOn(p);const shotLane=!laneBlocked(p.pos,new V(gx,H/2),p.team);if(distGoal<315&&danger&&shotLane&&Math.random()<(.055+.045*p.country.power*BAL.ai))return shoot(p,clamp(.48+.34*p.country.power+rand(-.08,.12),.38,1));const through=bestThroughRunner(p);if(through&&Math.random()<(.035+.030*p.country.pass*BAL.ai+.018*pressure)){lobPassToRunner(p,through.player,through.point,clamp(.48+through.score*.002,.42,.82));return}const mate=bestTacticalMate(p);if(mate&&((pressure>0&&Math.random()<.09+.04*pressure)||Math.random()<.028+.032*p.country.pass*BAL.ai)){targetPass(p,mate.player,false);if(Math.random()<.34){oneTwo={from:mate.player,returnTo:p,t:1.6};mate.player.forcedTarget={pos:mate.player.pos.clone().add(new V(ownDir*76,(mate.player.i%2?1:-1)*18)),t:82}}return}const nearest=nearestOpponent(p);let avoid=new V(0,0);if(nearest&&V.dist(nearest.pos,p.pos)<86){avoid=p.pos.clone().sub(nearest.pos).norm().mul(.38)}const laneY=H/2+Math.sin((gameTick+p.i*37)*.018)*42+(p.role==='striker'?(p.i%2?28:-28):0);const drive=new V(ownDir,(laneY-p.pos.y)*.004).add(avoid).norm();p.vel.add(drive.mul(.145*BAL.speed*(.92+.45*attack)*(pressure?1.08:1)));if(pressure>1&&Math.random()<.018)manualPassIntoSpace(p)}
function pressureOn(p){let n=0;for(const o of players){if(o.dead||o.team===p.team)continue;const d=V.dist(o.pos,p.pos);if(d<72)n++;else if(d<118)n+=.45}return n}
function nearestOpponent(p){let b=null,d=1e9;for(const o of players){if(o.dead||o.team===p.team)continue;const dd=V.dist(o.pos,p.pos);if(dd<d){d=dd;b=o}}return b}
function isDangerZone(carrier,team){const ownGoalX=team===TA?field.x:field.x+field.w;return Math.abs(carrier.pos.x-ownGoalX)<360||Math.abs(carrier.pos.y-H/2)<120}
