function secondClosestToBall(team){const arr=players.filter(p=>!p.dead&&p.team===team&&p.role!=='keeper').map(p=>({p,d:V.dist(p.pos,ball.owner?ball.owner.pos:ball.pos)})).sort((a,b)=>a.d-b.d);return arr[1]?arr[1].p:null}
function interceptPointFor(p){const lead=ball.z>18?10:7;return ball.pos.clone().add(ball.vel.clone().mul(lead)).add(new V(0,ball.vz>1?-8:0))}
function bestInterceptor(team){let b=null,score=1e9;for(const p of players){if(p.dead||p.team!==team||p.role==='keeper')continue;const ip=interceptPointFor(p);const d=V.dist(p.pos,ip)/(p.country.speed*(p.role==='striker'?1.05:1));const forward=team===TA?ip.x-p.pos.x:p.pos.x-ip.x;const s=d-forward*.08+(p.role==='mid'?-18:0);if(s<score){score=s;b=p}}return b}
function bestTacticalMate(p){const mates=players.filter(m=>m.team===p.team&&m!==p&&!m.dead);let best=null,score=-1e9;const gx=p.team===TA?field.x+field.w:field.x;for(const m of mates){const d=V.dist(p.pos,m.pos);const forward=p.team===TA?m.pos.x-p.pos.x:p.pos.x-m.pos.x;const lane=Math.abs(m.pos.y-p.pos.y);const goalGain=Math.abs(p.pos.x-gx)-Math.abs(m.pos.x-gx);let s=forward*.22+goalGain*.18-d*.05-lane*.025;if(m.role==='striker')s+=24;if(m.role==='mid'&&pressureOn(p)>0)s+=18;if(laneBlocked(p.pos,m.pos,p.team))s-=70;if(pressureOn(m)>1)s-=22;if(s>score){score=s;best=m}}return best?{player:best,score}:null}
function bestThroughRunner(p){const ownDir=p.team===TA?1:-1;let best=null,score=-1e9,point=null;for(const m of players){if(m.team!==p.team||m===p||m.dead||m.role==='defender')continue;const forward=p.team===TA?m.pos.x-p.pos.x:p.pos.x-m.pos.x;if(forward<-20)continue;const runPoint=m.pos.clone().add(new V(ownDir*(150+(m.role==='striker'?90:45)),(m.i%2?1:-1)*24));runPoint.x=clamp(runPoint.x,field.x+80,field.x+field.w-80);runPoint.y=clamp(runPoint.y,field.y+60,field.y+field.h-60);let s=forward*.34+(m.role==='striker'?50:20)-V.dist(p.pos,runPoint)*.045-pressureOn(m)*18;if(laneBlocked(p.pos,runPoint,p.team))s-=38;if(s>score){score=s;best=m;point=runPoint}}return best&&score>42?{player:best,point,score}:null}
function lobPassToRunner(p,runner,point,charge){sfxPass(true,charge);const dir=point.clone().sub(p.pos).norm();const pow=(8.0+charge*4.2)*BAL.pass*p.country.pass;release(dir,pow,6.8+charge*7.5);ball.lastKicker=p;runner.forcedTarget={pos:point,t:145};pop(p.pos.x,p.pos.y,'#ffffff',14);show('OUVERTURE LOBÉE !')}
function closestToBall(team){let b=null,d=1e9;for(const p of players){if(p.dead||p.team!==team||p.role==='keeper')continue;const dd=V.dist(p.pos,ball.owner?ball.owner.pos:ball.pos);if(dd<d){d=dd;b=p}}return b}
function switchPlayer(){const list=players.filter(p=>p.team===TA&&!p.dead);let b=null,d=1e9;const ref=ball.owner?ball.owner.pos:ball.pos;for(const p of list){if(p===controlled||p===controlled2)continue;const dd=V.dist(p.pos,ref);if(dd<d){d=dd;b=p}}if(b){setControl(b);show('P1 : '+b.name)}}function switchPlayer2(){if(controlMode==='solo')return;const team=controlMode==='pvp'?TB:TA;const list=players.filter(p=>p.team===team&&!p.dead);let b=null,d=1e9;const ref=ball.owner?ball.owner.pos:ball.pos;for(const p of list){if(p===controlled||p===controlled2)continue;const dd=V.dist(p.pos,ref);if(dd<d){d=dd;b=p}}if(b){setControl2(b);show('P2 : '+b.name)}}function setControl(p){players.forEach(x=>x.control=false);controlled=p;if(p){p.control=true;p.control2=false;if(p===controlled2)controlled2=null}}function setControl2(p){players.forEach(x=>x.control2=false);controlled2=p;if(p){p.control2=true;p.control=false;if(p===controlled)controlled=null}}
function laneBlocked(a,b,team){for(const p of players){if(p.dead||p.team===team)continue;if(distSeg(p.pos,a,b)<20)return true}return false}function distSeg(p,a,b){const ab=b.clone().sub(a),ap=p.clone().sub(a),l=ab.x*ab.x+ab.y*ab.y;let t=l?(ap.x*ab.x+ap.y*ab.y)/l:0;t=clamp(t,0,1);return V.dist(p,new V(a.x+ab.x*t,a.y+ab.y*t))}
const GOAL_SCORE_MAX_Z=24;
const GOAL_CROSSBAR_Z=29;
function goal(team,hitY=H/2){sfxGoal();team===TA?scoreA++:scoreB++;if(team===TA)netFxR={y:hitY,t:1,power:1};else netFxL={y:hitY,t:1,power:1};confettiBurst();show(team===TA?'BUUUUT ! PUBLIC EN FOLIE':'BUT ENCAISSÉ');shake=18;pendingKick=team===TA?TB:TA;goalHoldT=2.35;goalSlow=1.15;goalText.textContent=(team===TA?teamA.name:teamB.name)+' marque. Remise en jeu : '+(pendingKick===TA?teamA.name:teamB.name);goalPause.style.display='flex';if(mode==='campaign'&&scoreA>=3){campaignStep++;show('VICTOIRE DE CAMPAGNE !')}}function inGoal(y){return Math.abs(y-H/2)<field.goal/2}function canScoreBall(b){return inGoal(b.pos.y)&&b.z<GOAL_SCORE_MAX_Z}
function update(dt){pollGamepad();audioFrame(dt);gameTick+=dt*60;updateWeather(dt);updateCamera(dt);if(netFxL.t>0)netFxL.t=Math.max(0,netFxL.t-dt*2.6);if(netFxR.t>0)netFxR.t=Math.max(0,netFxR.t-dt*2.6);if(menu.style.display!=='none'){menuNavFrame();clearInput();return}if(gamePaused){updateCrowd(dt);clearInput();return}if(pressed.r)startGame(mode);const skip=actionPress('pass')||actionPress('shoot')||pressed.enter;if(preMatchT>0){preMatchT-=dt;if(skip)preMatchT=0;if(preMatchT<=0)matchIntro.style.display='none';updateCelebrationFX(dt);clearInput();return}if(goalHoldT>0){const sdt=dt*.25;goalHoldT-=dt;if(skip)goalHoldT=0;updateCelebrationFX(dt);particlesStep(sdt);if(goalHoldT<=0){goalPause.style.display='none';if(mode==='friendly'&&(scoreA>=3||scoreB>=3)){gameOver=true;showEnd()}else{beginKickoffSequence(pendingKick||TA);pendingKick=null}}clearInput();return}if(kickoffSetupT>0){kickoffUpdate(dt);updateCelebrationFX(dt);clearInput();return}const realDt=goalSlow>0?dt*.45:dt;if(goalSlow>0)goalSlow-=dt;timer-=dt;if(timer<=0&&mode!=='training'){timer=0;gameOver=true;if(!winShown)showEnd()}if(gameOver){updateCelebrationFX(dt);if(Math.random()<.06)fireworkBurst(rand(110,W-110),rand(70,230));clearInput();return}if(oneTwo){oneTwo.t-=realDt;if(oneTwo.t<=0)oneTwo=null}players.forEach(p=>p.update());ball.update();particlesStep(realDt);updateCelebrationFX(dt);if(toastT>0){toastT-=dt;if(toastT<=0)toast.style.opacity=0}clearInput()}
function particlesStep(dt){const f=dt*60;particles.forEach(p=>{p.x+=p.vx*f;p.y+=p.vy*f;p.vx*=Math.pow(.93,f);p.vy*=Math.pow(.93,f);p.life-=f});particles=particles.filter(p=>p.life>0)}function updateCelebrationFX(dt){const f=dt*60;if(gameOver&&Math.random()<.45){const colors=['#ffd34a','#ff3333','#53d7ff','#ffffff','#35e86b'];confetti.push({x:rand(0,W),y:rand(-30,20),vx:rand(-1.2,1.2),vy:rand(1,3.2),life:rand(80,150),s:rand(3,7),c:colors[Math.floor(rand(0,colors.length))]})}confetti.forEach(c=>{c.x+=c.vx*f;c.y+=c.vy*f;c.vy+=.05*f;c.life-=f});confetti=confetti.filter(c=>c.life>0);fireworks.forEach(fw=>{fw.x+=fw.vx*f;fw.y+=fw.vy*f;fw.vy+=.025*f;fw.life-=f});fireworks=fireworks.filter(fw=>fw.life>0)}function draw(){ctx.clearRect(0,0,W,H);ctx.save();let sx=0,sy=0;if(shake>0){sx=rand(-shake,shake);sy=rand(-shake,shake);shake*=.86;if(shake<.4)shake=0}ctx.translate(cam.x+sx,cam.y+sy);fieldDraw();drawBench();drawBlood();drawPassGuide();players.slice().sort((a,b)=>a.pos.y-b.pos.y).forEach(p=>p.draw());ball.draw();drawCharge();drawParticles();ctx.restore();drawWeather();drawDayMood();drawVignette();drawConfetti();drawFireworks();topUi.innerHTML=`${teamA.name} <span style="color:#ffd34a">${scoreA}</span> - <span style="color:#ffd34a">${scoreB}</span> ${mode==='training'?'TUTO':teamB.name} · ⏱ ${Math.ceil(timer)}`;if(gameOver)gameOverDraw()}
function drawGoalFrame(side,color,fx){const frontX=side==='left'?field.x:field.x+field.w;const backX=side==='left'?field.x-18:field.x+field.w+18;const sign=side==='left'?-1:1;const top=H/2-field.goal/2,bot=H/2+field.goal/2;ctx.fillStyle='rgba(255,255,255,.05)';ctx.beginPath();ctx.moveTo(frontX,top);ctx.lineTo(backX,top+10);ctx.lineTo(backX,bot-10);ctx.lineTo(frontX,bot);ctx.closePath();ctx.fill();ctx.strokeStyle=color;ctx.lineWidth=4;ctx.beginPath();ctx.moveTo(frontX,top);ctx.lineTo(backX,top+10);ctx.lineTo(backX,bot-10);ctx.lineTo(frontX,bot);ctx.stroke();ctx.strokeStyle='rgba(255,255,255,.45)';ctx.lineWidth=1.5;for(let i=0;i<=6;i++){const yy=top+i*(field.goal/6);const bend=fx.t>0?sign*Math.max(0,1-Math.abs(yy-fx.y)/42)*14*fx.t:0;ctx.beginPath();ctx.moveTo(frontX,yy);ctx.lineTo(backX+bend,yy);ctx.stroke()}for(let i=1;i<=4;i++){const dep=i/4;const bend=fx.t>0?sign*9*fx.t*(1-dep):0;ctx.beginPath();ctx.moveTo(frontX+sign*dep*2,top+i*4);ctx.lineTo(frontX+sign*(backX-frontX)*dep+bend,top+10+(bot-top-20)*dep);ctx.stroke()}}function fieldDraw(){ctx.fillStyle='#13241b';ctx.fillRect(0,0,W,H);const bg=ctx.createLinearGradient(0,field.y,0,field.y+field.h);if(matchEnv.tod==='morning'){bg.addColorStop(0,'#3d8b55');bg.addColorStop(1,'#245f39')}else if(matchEnv.tod==='evening'){bg.addColorStop(0,'#4a9258');bg.addColorStop(1,'#285536')}else{bg.addColorStop(0,'#3f9356');bg.addColorStop(1,'#27633d')}ctx.fillStyle=bg;ctx.fillRect(field.x,field.y,field.w,field.h);for(let i=0;i<12;i++){ctx.fillStyle=i%2?'rgba(255,255,255,.045)':'rgba(0,0,0,.045)';ctx.fillRect(field.x+i*field.w/12,field.y,field.w/12,field.h)}for(let i=0;i<180;i++){const gx=field.x+((i*53)%field.w),gy=field.y+((i*97)%field.h);ctx.fillStyle=i%3===0?'rgba(255,255,255,.022)':'rgba(12,58,28,.09)';ctx.fillRect(gx,gy,2,2)}for(let i=0;i<90;i++){const gx=field.x+((i*71)%field.w),gy=field.y+((i*41)%field.h);ctx.strokeStyle='rgba(88,176,109,.10)';ctx.lineWidth=1;ctx.beginPath();ctx.moveTo(gx,gy);ctx.lineTo(gx+3,gy-3);ctx.stroke()}ctx.fillStyle='rgba(255,255,255,.04)';ctx.fillRect(field.x-2,H/2-field.goal/2-12,44,field.goal+24);ctx.fillRect(field.x+field.w-42,H/2-field.goal/2-12,44,field.goal+24);ctx.strokeStyle='rgba(255,255,255,.58)';ctx.lineWidth=3;ctx.strokeRect(field.x,field.y,field.w,field.h);ctx.beginPath();ctx.moveTo(W/2,field.y);ctx.lineTo(W/2,field.y+field.h);ctx.stroke();ctx.beginPath();ctx.arc(W/2,H/2,62,0,Math.PI*2);ctx.stroke();ctx.beginPath();ctx.arc(W/2,H/2,3.2,0,Math.PI*2);ctx.fillStyle='rgba(255,255,255,.7)';ctx.fill();ctx.strokeRect(field.x,H/2-95,96,190);ctx.strokeRect(field.x+field.w-96,H/2-95,96,190);drawGoalFrame('left',teamKit(TA).color,netFxL);drawGoalFrame('right',teamKit(TB).color,netFxR)}
function drawBlood(){bloodDecals.forEach(b=>{ctx.globalAlpha=b.a;ctx.fillStyle=b.c;ctx.fillRect(b.x-b.s/2,b.y-b.s/2,b.s,b.s)});ctx.globalAlpha=1}
function gore(x,y,n){for(let i=0;i<n;i++){const vx=rand(-7,7),vy=rand(-7,7),c=Math.random()>.35?'#c40000':'#700000';particles.push({x,y,vx,vy,life:rand(18,42),c,s:rand(3,8)});bloodDecals.push({x:clamp(x+vx*5,field.x,field.x+field.w),y:clamp(y+vy*5,field.y,field.y+field.h),s:rand(5,16),c,a:rand(.55,.95)})}}
function dirtBurst(x,y,dir,n){for(let i=0;i<n;i++){const side=rand(-1.8,1.8);particles.push({x:x+rand(-4,4),y:y+rand(-3,3),vx:dir.x*rand(.8,2.4)+side,vy:dir.y*rand(.8,2.4)+rand(-1.6,.6),life:rand(12,24),c:Math.random()>.4?'#6f4a25':'#8c6a34',s:rand(2,5)})}}
function brutalKO(victim,killer,msg){sfxTackle(true);victim.dead=true;victim.respawn=9999;victim.hasBall=false;if(ball.owner===victim)ball.owner=null;gore(victim.pos.x,victim.pos.y,52);pop(victim.pos.x,victim.pos.y,'#ffdf2e',22);shake+=18;show(msg+' '+victim.name);const sub=callSubstituteFor(victim);if(victim===controlled){if(sub)setControl(sub);else switchPlayer()}}
function wallHit(x,y){pop(x,y,'#ffffff',7);if(ball.vel.len()>12)pop(x,y,'#ff3b19',10);shake+=2}
function drawPassGuide(){if(!controlled||!controlled.hasBall)return;let target=null;if(oneTwo&&oneTwo.returnTo){target=oneTwo.returnTo}else{const bm=bestMate(controlled);target=bm?bm.player:null}if(!target||!target.pos)return;ctx.save();ctx.setLineDash([6,8]);ctx.strokeStyle=oneTwo?'#53d7ff':'rgba(255,255,255,.45)';ctx.lineWidth=2;ctx.beginPath();ctx.moveTo(controlled.pos.x,controlled.pos.y);ctx.lineTo(target.pos.x,target.pos.y);ctx.stroke();ctx.restore()}
function drawCharge(){if(!controlled)return;const charge=Math.max(shootCharge,passCharge);if(charge<=0)return;const x=controlled.pos.x-24,y=controlled.pos.y-36;ctx.fillStyle='rgba(0,0,0,.55)';ctx.fillRect(x,y,48,7);ctx.fillStyle=passCharge>shootCharge?'#ffffff':shootCharge>.75?'#ff3333':'#ffd34a';ctx.fillRect(x,y,48*charge,7)}
function drawParticles(){particles.forEach(p=>{ctx.globalAlpha=clamp(p.life/30,0,1);ctx.fillStyle=p.c;ctx.fillRect(p.x,p.y,p.s,p.s)});ctx.globalAlpha=1}
function drawConfetti(){confetti.forEach(c=>{ctx.fillStyle=c.c;ctx.fillRect(c.x,c.y,c.s,c.s)})}
function drawFireworks(){fireworks.forEach(fw=>{ctx.globalAlpha=clamp(fw.life/55,0,1);ctx.fillStyle=fw.c;ctx.fillRect(fw.x,fw.y,fw.s,fw.s)});ctx.globalAlpha=1}
function gameOverDraw(){}
function pop(x,y,c,n){for(let i=0;i<n;i++)particles.push({x,y,vx:rand(-3,3),vy:rand(-3,3),life:rand(12,28),c,s:rand(2,5)})}function confettiBurst(){const colors=['#ffd34a','#ff3333','#53d7ff','#ffffff','#35e86b'];for(let i=0;i<160;i++)confetti.push({x:rand(0,W),y:rand(-40,80),vx:rand(-1.5,1.5),vy:rand(1,4),life:rand(80,150),s:rand(3,7),c:colors[i%colors.length]})}function fireworkBurst(x,y){const colors=['#ffd34a','#ff3333','#53d7ff','#ffffff','#35e86b'];for(let i=0;i<38;i++){const a=Math.PI*2*i/38,sp=rand(1.5,4.4);fireworks.push({x,y,vx:Math.cos(a)*sp,vy:Math.sin(a)*sp,life:rand(35,70),s:rand(3,6),c:colors[i%colors.length]})}}function showEnd(){winShown=true;endTitle.textContent=scoreA>scoreB?'VICTOIRE !':scoreA<scoreB?'DÉFAITE...':'MATCH NUL';endScore.textContent=teamA.name+' '+scoreA+' - '+scoreB+' '+teamB.name;endOverlay.style.display='flex';confettiBurst();for(let i=0;i<5;i++)fireworkBurst(rand(120,W-120),rand(80,260))}
function show(t){toast.textContent=t;toast.style.opacity=1;toastT=1.7}
let simAcc=0;function loop(now){try{const dt=Math.min((now-last)/1000,.05);last=now;simAcc+=dt;const step=1/60;let n=0;while(simAcc>=step&&n<6){update(step);simAcc-=step;n++;}if(n===6)simAcc=0;draw()}catch(err){dbgError(err)}requestAnimationFrame(loop)}
function actionPress(a){return pressed[actionKey(a)]||mobPressed[a]||gpPressed[a]}function actionRelease(a){return released[actionKey(a)]||mobReleased[a]||gpReleased[a]}function actionKey(a){return {pass:' ',tackle:'c',sprint:'shift',switch:'tab',shoot:'x'}[a]}function showPlayerGauges(){return debugPanel&&debugPanel.classList.contains('open')}

function showIntro(){introTeams.textContent=teamA.name+'  contre  '+teamB.name;introStats.innerHTML=`<b>Capitaines</b> : ${captainName(TA)}  vs  ${captainName(TB)}<br>${stars(teamA.speed)} Vitesse · ${stars(teamA.power)} Tir · ${stars(teamA.pass)} Passe · ${stars(teamA.tackle)} Tacle<br>${stars(teamB.speed)} Vitesse · ${stars(teamB.power)} Tir · ${stars(teamB.pass)} Passe · ${stars(teamB.tackle)} Tacle`;matchIntro.style.display='flex'}
function stars(v){return v>=1.12?'★★★':v>=1.02?'★★☆':v>=.96?'★☆☆':'☆☆☆'}
function initDebug(){document.querySelectorAll('#debugPanel input[data-bal]').forEach(inp=>{const k=inp.dataset.bal;inp.value=BAL[k];const val=document.querySelector(`[data-val="${k}"]`);const sync=()=>{BAL[k]=parseFloat(inp.value);if(val)val.textContent=BAL[k].toFixed(2)};inp.addEventListener('input',sync);sync()})}
function isMobileLike(){return matchMedia('(hover:none), (pointer:coarse)').matches||innerWidth<980||innerHeight<560}
async function requestLandscapeMode(){
  if(!isMobileLike())return;
  const root=document.documentElement;
  try{if(root.requestFullscreen&&!document.fullscreenElement){await root.requestFullscreen({navigationUI:'hide'}).catch(()=>{});}}catch(_){ }
  try{if(screen.orientation&&screen.orientation.lock){await screen.orientation.lock('landscape').catch(()=>{});}}catch(_){ }
}
const MOBILE_INPUT_Y_FIX=-30; // corrige le décalage tactile observé en paysage mobile: hitbox navigateur plus basse que le visuel.
function inputPoints(x,y){
  const vv=window.visualViewport;
  const pts=[{x,y},{x,y:y+MOBILE_INPUT_Y_FIX},{x,y:y-MOBILE_INPUT_Y_FIX}];
  if(vv){pts.push({x:x+vv.offsetLeft,y:y+vv.offsetTop},{x:x+vv.offsetLeft,y:y+vv.offsetTop+MOBILE_INPUT_Y_FIX});}
  return pts;
}
function mobileButtonAt(x,y){
  let best=null,bestScore=Infinity;
  const pts=inputPoints(x,y);
  
const savedBtns=localStorage.getItem('brutal_fc_mobileBtns');if(savedBtns){try{const p=JSON.parse(savedBtns);mobileBtns.style.left=p.left;mobileBtns.style.top=p.top;mobileBtns.style.right='auto';mobileBtns.style.bottom='auto'}catch(_){}}
let btnDrag=null;
mobileBtns.addEventListener('pointerdown',e=>{if(!gamePaused)return;if(!e.target.closest('.mbtn'))return;btnDrag={id:e.pointerId,ox:e.clientX-mobileBtns.getBoundingClientRect().left,oy:e.clientY-mobileBtns.getBoundingClientRect().top};try{mobileBtns.setPointerCapture(e.pointerId)}catch(_){}});
mobileBtns.addEventListener('pointermove',e=>{if(!btnDrag||e.pointerId!==btnDrag.id)return;const x=clamp(e.clientX-btnDrag.ox,6,innerWidth-mobileBtns.offsetWidth-6),y=clamp(e.clientY-btnDrag.oy,6,innerHeight-mobileBtns.offsetHeight-6);mobileBtns.style.left=x+'px';mobileBtns.style.top=y+'px';mobileBtns.style.right='auto';mobileBtns.style.bottom='auto'});
function saveMobileButtons(){if(!btnDrag)return;localStorage.setItem('brutal_fc_mobileBtns',JSON.stringify({left:mobileBtns.style.left,top:mobileBtns.style.top}));btnDrag=null}
mobileBtns.addEventListener('pointerup',saveMobileButtons);mobileBtns.addEventListener('pointercancel',saveMobileButtons);

document.querySelectorAll('.mbtn').forEach(b=>{
    const r=b.getBoundingClientRect();
    const pad=34; // marge volontaire: le doigt humain n'est pas un curseur laser, incroyable mais vrai.
    for(const p of pts){
      if(p.x>=r.left-pad&&p.x<=r.right+pad&&p.y>=r.top-pad&&p.y<=r.bottom+pad){
        const cx=r.left+r.width*.5,cy=r.top+r.height*.5;
        const score=Math.hypot(p.x-cx,p.y-cy);
        if(score<bestScore){best=b;bestScore=score;}
      }
    }
  });
  return best;
}
function forceMobileButton(action,isDown){if(!action)return;const btn=document.querySelector(`.mbtn[data-action="${action}"]`);if(isDown){if(!mobDown[action])mobPressed[action]=true;mobDown[action]=true;if(btn)btn.classList.add('down')}else{if(mobDown[action])mobReleased[action]=true;mobDown[action]=false;if(btn)btn.classList.remove('down')}}

function pollGamepad(){gpMove.x=0;gpMove.y=0;gp2Move.x=0;gp2Move.y=0;for(const k in gpPressed)delete gpPressed[k];for(const k in gpReleased)delete gpReleased[k];for(const k in gp2Pressed)delete gp2Pressed[k];for(const k in gp2Released)delete gp2Released[k];const pads=navigator.getGamepads?navigator.getGamepads():[];function readPad(g,move,down,pressedMap,releasedMap,prev){if(!g)return;let x=g.axes[0]||0,y=g.axes[1]||0;const l=Math.hypot(x,y);if(l>0.18){const power=Math.min(1,(l-0.18)/0.82);move.x=x/l*power;move.y=y/l*power}else{move.x=0;move.y=0}for(const action in GP_MAP){const isDown=GP_MAP[action].some(i=>g.buttons[i]&&g.buttons[i].pressed);if(isDown&&!prev[action])pressedMap[action]=true;if(!isDown&&prev[action])releasedMap[action]=true;down[action]=isDown;prev[action]=isDown}}const connected=[...pads].filter(p=>p&&p.connected);readPad(connected[0],gpMove,gpDown,gpPressed,gpReleased,gpPrev);readPad(connected[1],gp2Move,gp2Down,gp2Pressed,gp2Released,gp2Prev)}
addEventListener('keydown',e=>{const k=e.key.toLowerCase();if(!keys[k])pressed[k]=true;keys[k]=true;if(k==='tab')e.preventDefault()});addEventListener('keyup',e=>{const k=e.key.toLowerCase();keys[k]=false;released[k]=true});
function clearInput(){for(const k in pressed)delete pressed[k];for(const k in released)delete released[k];for(const k in mobPressed)delete mobPressed[k];for(const k in mobReleased)delete mobReleased[k];for(const k in gpPressed)delete gpPressed[k];for(const k in gpReleased)delete gpReleased[k];for(const k in gp2Pressed)delete gp2Pressed[k];for(const k in gp2Released)delete gp2Released[k]}
const stick=document.getElementById('stick'),nub=document.getElementById('nub'),mobileBtns=document.getElementById('mobileBtns');let sid=null,origin=null;
function mobileControlsVisible(){return getComputedStyle(mobileControls).display!=='none'&&menu.style.display==='none'}
function placeDynamicStick(x,y){const size=stick.offsetWidth||132;stick.style.left=(x-size*.5)+'px';stick.style.top=(y-size*.5)+'px';stick.style.bottom='auto';origin={x,y:y+MOBILE_INPUT_Y_FIX};stick.classList.add('active');nub.style.transform='translate(0,0)'}
stick.addEventListener('pointerdown',e=>{e.preventDefault();sid=e.pointerId;try{stick.setPointerCapture(sid)}catch(_){}placeDynamicStick(e.clientX,e.clientY);stickMove(e)});
stick.addEventListener('pointermove',e=>{if(e.pointerId===sid)stickMove(e)});
stick.addEventListener('pointerup',stickEnd);stick.addEventListener('pointercancel',stickEnd);
addEventListener('pointerdown',e=>{if(!mobileControlsVisible())return;if(e.target.closest('.mbtn')||e.target.closest('#hudBtns')||e.target.closest('#pauseOverlay')||e.target.closest('#endOverlay'))return;if(sid!==null)return;e.preventDefault();sid=e.pointerId;placeDynamicStick(e.clientX,e.clientY);stickMove(e)},{capture:true,passive:false});
addEventListener('pointermove',e=>{if(e.pointerId===sid)stickMove(e)},{capture:true,passive:false});
function stickMove(e){
  if(!origin)return;
  let dx=e.clientX-origin.x;
  let dy=e.clientY-origin.y;
  const l=Math.hypot(dx,dy);
  const max=42;
  if(l<10){mobileMove.x=0;mobileMove.y=0;dx=0;dy=0;}
  else{
    const cl=Math.min(l,max);
    dx=dx/l*cl;dy=dy/l*cl;
    const power=Math.min(1,Math.max(0,(l-10)/(max-10)));
    mobileMove.x=(dx/l)*power;
    mobileMove.y=(dy/l)*power*(dy>0?1.16:1.0);
    mobileMove.y=Math.max(-1,Math.min(1,mobileMove.y));
  }
  nub.style.transform=`translate(${dx}px,${dy}px)`;
}
function stickEnd(e){if(e&&sid!==null&&e.pointerId!==sid)return;sid=null;origin=null;mobileMove.x=0;mobileMove.y=0;nub.style.transform='translate(0,0)';stick.classList.remove('active')}
document.querySelectorAll('.mbtn').forEach(b=>{const a=b.dataset.action;let active=false;function down(e){if(e)e.preventDefault();if(active)return;active=true;mobPressed[a]=true;mobDown[a]=true;b.classList.add('down')}function up(e){if(e)e.preventDefault();if(!active)return;active=false;mobReleased[a]=true;mobDown[a]=false;b.classList.remove('down')}b.addEventListener('pointerdown',e=>{try{b.setPointerCapture(e.pointerId)}catch(_){}down(e)});b.addEventListener('pointerup',up);b.addEventListener('pointercancel',up);b.addEventListener('touchstart',down,{passive:false});b.addEventListener('touchend',up,{passive:false});b.addEventListener('mousedown',down);b.addEventListener('mouseup',up);b.addEventListener('click',e=>e.preventDefault())});
// Fallback anti-hitbox décalée : si le navigateur envoie l'événement au mauvais calque,
// on recalcule le bouton sous le doigt avec getBoundingClientRect().
addEventListener('pointerdown',e=>{const b=mobileButtonAt(e.clientX,e.clientY);if(!b)return;e.preventDefault();forceMobileButton(b.dataset.action,true)},{capture:true,passive:false});
addEventListener('pointerup',e=>{for(const k of ['pass','shoot','tackle','sprint','switch'])forceMobileButton(k,false)},{capture:true,passive:false});
addEventListener('pointercancel',e=>{for(const k of ['pass','shoot','tackle','sprint','switch'])forceMobileButton(k,false)},{capture:true,passive:false});
addEventListener('touchstart',e=>{const t=e.changedTouches&&e.changedTouches[0];if(!t)return;const b=mobileButtonAt(t.clientX,t.clientY);if(!b)return;e.preventDefault();forceMobileButton(b.dataset.action,true)},{capture:true,passive:false});
addEventListener('touchend',e=>{for(const k of ['pass','shoot','tackle','sprint','switch'])forceMobileButton(k,false)},{capture:true,passive:false});


addEventListener('pointerdown',resumeAudio,{once:true,passive:true});addEventListener('keydown',resumeAudio,{once:true,passive:true});
function clamp(v,a,b){return Math.max(a,Math.min(b,v))}function rand(a,b){return a+Math.random()*(b-a)}
